#include <stdio.h>
#include <stdlib.h>
#include <unistd.h>
#include <sys/wait.h>

int main() {
 pid_t pid = fork();

 if (pid < 0) {
 perror("fork failed");
 exit(1);
 }

 if (pid == 0) {
 // Child process
 printf("Child executing, PID = %d\n", getpid());
 // Simulate some work
 sleep(2);
 printf("Child exiting with status 42\n");
 exit(42);
 } else {
 // Parent process
 int status;
 printf("Parent waiting for child (PID = %d)\n", pid);
 pid_t child_pid = wait(&status);

 if (WIFEXITED(status)) {
 printf("Child %d terminated normally\n", child_pid);
 printf("Exit status: %d\n", WEXITSTATUS(status));
 }
 }
 return 0;
}

#include <stdio.h>
#include <stdlib.h>
#include <unistd.h>
#include <sys/wait.h>

int main() {
 pid_t pid = fork();

 if (pid == 0) {
 // Child does quick work
 printf("Child working...\n");
 sleep(1);
 exit(0);
 }

 // Parent checks child without blocking
 int status;
 while (1) {
 pid_t result = waitpid(pid, &status, WNOHANG);

 if (result == 0) {
 printf("Child not yet finished, doing other work...\n");
 sleep(0.5);
 } else if (result == pid) {
 printf("Child finished!\n");
 break;
 } else {
 perror("waitpid error");
 break;
 }
 }
 return 0;
}

#include <stdio.h>
#include <stdlib.h>
#include <unistd.h>
#include <sys/wait.h>

int main() {
 int n = 3;

 for (int i = 0; i < n; i++) {
 pid_t pid = fork();

 if (pid == 0) {
 // Each child does different work
 printf("Child %d (PID %d) working\n", i, getpid());
 sleep(i + 1); // Different sleep times
 exit(i * 10); // Different exit codes
 }
 }

 // Parent waits for all children
 int children = n;
 while (children > 0) {
 int status;
 pid_t child_pid = wait(&status);

 if (child_pid > 0) {
 if (WIFEXITED(status)) {
 printf("Child %d exited with code %d\n", 
 child_pid, WEXITSTATUS(status));
 }
 children--;
 }
 }
 printf("All children reaped\n");
 return 0;
}

#include <stdio.h>
#include <stdlib.h>
#include <unistd.h>
#include <sys/wait.h>
#include <signal.h>

void check_status(int status) {
 if (WIFEXITED(status)) {
 printf("Normal exit, status = %d\n", WEXITSTATUS(status));
 } else if (WIFSIGNALED(status)) {
 printf("Killed by signal %d\n", WTERMSIG(status));
 } else if (WIFSTOPPED(status)) {
 printf("Stopped by signal %d\n", WSTOPSIG(status));
 } else if (WIFCONTINUED(status)) {
 printf("Continued\n");
 }
}

int main() {
 pid_t pid = fork();

 if (pid == 0) {
 // Child - demonstrate different termination
 printf("Child running, will exit normally\n");
 exit(25); // Normal exit with code 25
 }

 int status;
 wait(&status);
 check_status(status); // Will show: Normal exit, status = 25

 return 0;
}
